import React, { useRef, useMemo, useState, useEffect } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import "../style/NeuralParticles.css";

/* ══════════════════════════════════════════════════════
   Particle Neural Network
   ─ Nodes: 40 particles each, orbiting in vertex shader
   ─ Edges: 22 stream particles each, lerped on CPU
   ─ AdditiveBlending → glowing halos emerge from overlap
══════════════════════════════════════════════════════ */

const NODES = [
  // Input — x = -3
  { id: 0,  pos: [-3,  1.1,  0.2], layer: 0 },
  { id: 1,  pos: [-3,  0,   -0.3], layer: 0 },
  { id: 2,  pos: [-3, -1.1,  0.1], layer: 0 },
  // Hidden 1 — x = -1
  { id: 3,  pos: [-1,  1.7,  0.3], layer: 1 },
  { id: 4,  pos: [-1,  0.55,-0.2], layer: 1 },
  { id: 5,  pos: [-1, -0.55, 0.4], layer: 1 },
  { id: 6,  pos: [-1, -1.7, -0.1], layer: 1 },
  // Hidden 2 — x = 1
  { id: 7,  pos: [ 1,  1.7, -0.2], layer: 2 },
  { id: 8,  pos: [ 1,  0.55, 0.3], layer: 2 },
  { id: 9,  pos: [ 1, -0.55,-0.3], layer: 2 },
  { id: 10, pos: [ 1, -1.7,  0.2], layer: 2 },
  // Output — x = 3
  { id: 11, pos: [ 3,  0.8,  0.1], layer: 3 },
  { id: 12, pos: [ 3, -0.8, -0.1], layer: 3 },
];

// Fully-connected between consecutive layers
const EDGES = [];
for (let i = 0; i < NODES.length; i++) {
  for (let j = i + 1; j < NODES.length; j++) {
    if (NODES[j].layer === NODES[i].layer + 1) EDGES.push([i, j]);
  }
}

const CLUSTER = 40;  // particles per node (GPU-driven orbit)
const STREAM  = 22;  // particles per edge (CPU lerp)

/* ── Shaders ── */
const clusterVert = /* glsl */ `
  uniform float uTime;
  uniform float uSize;
  attribute vec3  aRandom;
  attribute float aScale;
  varying float   vBright;
  void main() {
    vec3 p = position;                              // node centre stored as base pos
    float r  = 0.13 + aRandom.y * 0.44;            // orbit radius
    float spd = 0.55 + aRandom.x * 2.2;            // orbit speed
    float ang = uTime * spd + aRandom.z * 6.2831;  // angle over time
    float tlt = aRandom.z * 3.14159;               // orbit-plane tilt
    p.x += cos(ang) * r;
    p.y += sin(ang) * r * cos(tlt);
    p.z += sin(ang) * r * sin(tlt);
    vec4 mv    = modelViewMatrix * vec4(p, 1.0);
    gl_Position  = projectionMatrix * mv;
    gl_PointSize = uSize * aScale / -mv.z;
    vBright = 0.55 + 0.45 * sin(ang + 0.5);
  }`;

const clusterFrag = /* glsl */ `
  varying float vBright;
  void main() {
    float d = length(gl_PointCoord - vec2(0.5));
    if (d > 0.5) discard;
    float s = pow(1.0 - d * 2.0, 3.0);
    vec3 col = mix(vec3(0.08, 0.3, 0.92), vec3(0.62, 0.86, 1.0), s) * vBright;
    gl_FragColor = vec4(col, s * 0.88);
  }`;

const streamVert = /* glsl */ `
  attribute float aProgress;
  varying  float vProgress;
  void main() {
    vProgress = aProgress;
    float fade = sin(aProgress * 3.14159);
    vec4 mv    = modelViewMatrix * vec4(position, 1.0);
    gl_Position  = projectionMatrix * mv;
    gl_PointSize = 42.0 * (0.3 + fade * 0.7) / -mv.z;
  }`;

const streamFrag = /* glsl */ `
  varying float vProgress;
  void main() {
    float d = length(gl_PointCoord - vec2(0.5));
    if (d > 0.5) discard;
    float glow = pow(1.0 - d * 2.0, 2.2);
    float fade = sin(vProgress * 3.14159);
    vec3  col  = mix(vec3(0.0, 0.88, 1.0), vec3(0.72, 0.22, 1.0), vProgress);
    gl_FragColor = vec4(col, glow * fade * 0.84);
  }`;

/* ── Thin static lines showing topology ── */
function NetworkLines() {
  const obj = useMemo(() => {
    const pts = new Float32Array(EDGES.length * 6);
    EDGES.forEach(([a, b], i) => {
      pts.set(NODES[a].pos, i * 6);
      pts.set(NODES[b].pos, i * 6 + 3);
    });
    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(pts, 3));
    const mat = new THREE.LineBasicMaterial({
      color: "#1a44cc",
      transparent: true,
      opacity: 0.18,
      blending: THREE.AdditiveBlending,
    });
    return new THREE.LineSegments(geo, mat);
  }, []);
  return <primitive object={obj} />;
}

/* ── Ambient background particles ── */
function BgParticles() {
  const geo = useMemo(() => {
    const N = 500, pos = new Float32Array(N * 3);
    for (let i = 0; i < N; i++) {
      pos[i * 3]     = (Math.random() - 0.5) * 18;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 10;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 6 - 2;
    }
    const g = new THREE.BufferGeometry();
    g.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    return g;
  }, []);
  return (
    <points geometry={geo}>
      <pointsMaterial color="#223399" size={0.016} transparent opacity={0.28}
        sizeAttenuation blending={THREE.AdditiveBlending} depthWrite={false} />
    </points>
  );
}

/* ── Main particle network ── */
function ParticleNet() {
  const groupRef   = useRef();
  const streamRef  = useRef();

  /* Cluster geometry — positions are node centres; shader does orbit */
  const { clusterGeo, clusterUni } = useMemo(() => {
    const n    = NODES.length * CLUSTER;
    const pos  = new Float32Array(n * 3);
    const rand = new Float32Array(n * 3);
    const scl  = new Float32Array(n);
    NODES.forEach((nd, ni) => {
      for (let p = 0; p < CLUSTER; p++) {
        const i = ni * CLUSTER + p;
        pos.set(nd.pos, i * 3);
        rand[i * 3]     = Math.random();
        rand[i * 3 + 1] = Math.random();
        rand[i * 3 + 2] = Math.random();
        scl[i]          = 0.4 + Math.random() * 0.6;
      }
    });
    const g = new THREE.BufferGeometry();
    g.setAttribute("position", new THREE.BufferAttribute(pos,  3));
    g.setAttribute("aRandom",  new THREE.BufferAttribute(rand, 3));
    g.setAttribute("aScale",   new THREE.BufferAttribute(scl,  1));
    return { clusterGeo: g, clusterUni: { uTime: { value: 0 }, uSize: { value: 82 } } };
  }, []);

  /* Stream geometry — particle positions updated every frame on CPU */
  const { streamGeo, sd } = useMemo(() => {
    const n       = EDGES.length * STREAM;
    const posA    = new Float32Array(n * 3);
    const posB    = new Float32Array(n * 3);
    const tArr    = new Float32Array(n);
    const spd     = new Float32Array(n);
    const livePos = new Float32Array(n * 3);
    const liveT   = new Float32Array(n);
    EDGES.forEach(([ai, bi], ei) => {
      const a = NODES[ai].pos, b = NODES[bi].pos;
      for (let p = 0; p < STREAM; p++) {
        const i = ei * STREAM + p;
        posA.set(a, i * 3); posB.set(b, i * 3);
        tArr[i] = p / STREAM;
        spd[i]  = 0.0025 + Math.random() * 0.004;
        const t = tArr[i];
        livePos[i*3]   = a[0] + (b[0]-a[0])*t;
        livePos[i*3+1] = a[1] + (b[1]-a[1])*t;
        livePos[i*3+2] = a[2] + (b[2]-a[2])*t;
        liveT[i] = t;
      }
    });
    const g = new THREE.BufferGeometry();
    g.setAttribute("position",
      new THREE.BufferAttribute(livePos, 3).setUsage(THREE.DynamicDrawUsage));
    g.setAttribute("aProgress",
      new THREE.BufferAttribute(liveT,   1).setUsage(THREE.DynamicDrawUsage));
    return { streamGeo: g, sd: { posA, posB, tArr, spd, livePos, liveT } };
  }, []);

  useFrame(({ clock }) => {
    clusterUni.uTime.value = clock.elapsedTime;

    // Advance stream particles
    const { posA, posB, tArr, spd, livePos, liveT } = sd;
    const n = EDGES.length * STREAM;
    for (let i = 0; i < n; i++) {
      tArr[i] += spd[i];
      if (tArr[i] > 1) tArr[i] -= 1;
      const t = tArr[i];
      livePos[i*3]   = posA[i*3]   + (posB[i*3]   - posA[i*3])   * t;
      livePos[i*3+1] = posA[i*3+1] + (posB[i*3+1] - posA[i*3+1]) * t;
      livePos[i*3+2] = posA[i*3+2] + (posB[i*3+2] - posA[i*3+2]) * t;
      liveT[i] = t;
    }
    streamGeo.attributes.position.needsUpdate = true;
    streamGeo.attributes.aProgress.needsUpdate = true;

    // Gentle sway
    if (groupRef.current) {
      const t = clock.elapsedTime;
      groupRef.current.rotation.y = Math.sin(t * 0.13) * 0.32;
      groupRef.current.rotation.x = Math.sin(t * 0.09) * 0.07;
    }
  });

  return (
    <group ref={groupRef}>
      <BgParticles />
      <NetworkLines />

      {/* Node clusters (GPU orbit via shader) */}
      <points geometry={clusterGeo}>
        <shaderMaterial
          uniforms={clusterUni}
          vertexShader={clusterVert}
          fragmentShader={clusterFrag}
          transparent depthWrite={false} blending={THREE.AdditiveBlending}
        />
      </points>

      {/* Edge stream particles (CPU lerp) */}
      <points ref={streamRef} geometry={streamGeo}>
        <shaderMaterial
          vertexShader={streamVert}
          fragmentShader={streamFrag}
          transparent depthWrite={false} blending={THREE.AdditiveBlending}
        />
      </points>
    </group>
  );
}

/* ── Lazy-mount wrapper ── */
function LazyCanvas({ children, ...props }) {
  const wrapRef = useRef();
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (wrapRef.current) obs.observe(wrapRef.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={wrapRef} style={{ width: "100%", height: "100%" }}>
      {visible && <Canvas {...props}>{children}</Canvas>}
    </div>
  );
}

const NeuralParticles = () => (
  <div className="neural-particles-wrap">
    <div className="neural-particles-canvas" aria-hidden="true">
      <LazyCanvas
        camera={{ position: [0, 0, 7], fov: 55 }}
        gl={{ antialias: true, alpha: false }}
        onCreated={({ gl }) => gl.setClearColor("#010108", 1)}
      >
        <ParticleNet />
      </LazyCanvas>
    </div>
    <div className="neural-particles-legend">
      <span className="np-legend-item"><span className="np-dot" style={{ background: "#60a5fa" }} />Input</span>
      <span className="np-legend-item"><span className="np-dot" style={{ background: "#c49a7a" }} />Hidden</span>
      <span className="np-legend-item"><span className="np-dot" style={{ background: "#34d399" }} />Output</span>
      <span className="np-legend-item np-stream">
        <span className="np-stream-line" />Signal stream
      </span>
    </div>
  </div>
);

export default NeuralParticles;
